import * as React from 'react';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import { Routes, Route, useNavigate, Navigate, Link } from 'react-router-dom';
import Projects from './Projects';
import Intro from './intro';
import Navbar from './Navbar';
import Resume from './resume';
import Stack from '@mui/material/Stack';
import Blogs from './blogs';
import Typography from '@mui/material/Typography';
import Copyright from './footnote';
import Fade from '@mui/material/Fade';
import myimg from '../images/IMG_9208.jpg';

export default function Home() {
	const [isVisible, setIsVisible] = React.useState(false);

	// Trigger the transition when the component mounts
	React.useEffect(() => {
	  setIsVisible(true);
	}, []);
  return (
    <Box>
      <Navbar />
      <Stack flexDirection={'column'}>
          <Intro />
          <Stack flexDirection={'row'} justifyContent={'center'} alignItems={'center'} margin={'20px'}>
              <Link to="/Projects" style={{ textDecoration: 'none' }}>
                <Button
                  variant="contained"
                  sx={{
                    backgroundColor: '#f50057',
                    color: 'white',
                    height: '100px', 
                    width: '300px',
                    marginTop: '50px',
                    '&:hover': {
                      backgroundColor: '#ff4081',
                    },
                    '&:hover, &:focus': {
                      boxShadow: '0 4px 8px rgba(0, 0, 0, 0.3)',
                    },
                    fontSize:'20px', fontWeight:'lighter'
                  }}
                >
                  Projects
                </Button>
              </Link>
              <Resume />
            </Stack>
			<Stack flexDirection={'column'}>
				<h1 id='blogs' style={{ textAlign: 'center',
						borderBottom: '2px solid black',
						paddingBottom: '10px',
						backgroundColor: 'black',
						marginLeft:'10%',
						marginRight:'10%'}}>
							Blogs</h1>
				<Blogs />
				
				<h1 id='contact-me' style={{ textAlign: 'center',
						borderBottom: '2px solid black',
						paddingBottom: '10px',
						backgroundColor: 'black',
						marginLeft:'10%',
						marginRight:'10%'}}>
							Contact Me</h1>
							<Stack flexDirection={{ xs: 'column', md: 'row' }} sx={{ display: 'flex' }}>
				<div style={{ marginLeft: '10%', marginRight: '30px' }}>
					<h2 style={{fontSize:'80px'}}>Reach out to me</h2>
					<h2>DISCUSS A PROJECT OR JUST WANT TO SAY HI? MY INBOX IS OPEN FOR ALL.</h2>
					<h2 style={{fontWeight:'bold'}}>"Cyber Secuity Enthusiast| MERN stack Developer | Still Finding 💭 "</h2>
					<h2>📍Karachi, Pakistan</h2>
					<h2>Open for opportunities: YES</h2>
				</div>
				<img src={myimg} alt="myself" style={{ width: '400px', borderRadius: '70%', border: '5px solid teal', display: 'flex' }} />
				</Stack>
			</Stack>
        </Stack>

		<Copyright />
    </Box>
  );
}